function normalizeRoleKey(role) {
  return String(role || '')
    .trim()
    .toLowerCase()
    .replace(/\s+/g, ' ')
}

/** Case-insensitive designation → skills (from roleSkillMap). */
const ROLE_SKILL_LOOKUP = (() => {
  const byNorm = new Map()
  for (const [role, skills] of Object.entries(roleSkillMap)) {
    if (role === '_general') continue
    if (!Array.isArray(skills) || !skills.length) continue
    byNorm.set(normalizeRoleKey(role), skills)
  }
  return byNorm
})()

/** Skills for a designation; empty array if not in roleSkillMap. */
export function getSkillsForRole(role) {
  const raw = String(role || '').trim()
  if (!raw) return []
  if (Array.isArray(roleSkillMap[raw]) && roleSkillMap[raw].length) return [...roleSkillMap[raw]]
  const hit = ROLE_SKILL_LOOKUP.get(normalizeRoleKey(raw))
  return hit ? [...hit] : []
}

function hashStr(s) {
  let h = 0
  for (let i = 0; i < s.length; i += 1) h = (h << 5) - h + s.charCodeAt(i)
  return Math.abs(h)
}

/** Up to 4 skills for a milestone role (Frame 3 detail panel). */
export function resolveMilestoneSkills(roleTitle, limit = 4) {
  const fromRole = getSkillsForRole(roleTitle)
  const general = Array.isArray(roleSkillMap._general) ? roleSkillMap._general : []
  const merged = [...new Set([...fromRole, ...general])]
  return merged.slice(0, limit)
}

/** Stable “live jobs on Apna” count in 550–800 range for a role title. */
export function apnaLiveJobsCountForRole(roleTitle) {
  const key = String(roleTitle || 'role').trim().toLowerCase()
  return 550 + (hashStr(key) % 251)
}

function allCatalogEntries() {
  const out = [...GENERIC_FRESHER_SKILLS, ...EXTRA_CATALOG]
  for (const rule of ROLE_RULES) out.push(...rule.skills)
  for (const skills of Object.values(roleSkillMap)) {
    if (Array.isArray(skills)) out.push(...skills)
  }
  return uniqSorted(out)
}

export const SKILL_SEARCH_CATALOG = allCatalogEntries()

/** @param {string} query */
export function searchSkillCatalog(query, limit = 48) {
  const q = String(query || '')
    .trim()
    .toLowerCase()
  if (!q) return SKILL_SEARCH_CATALOG.slice(0, limit)

  return SKILL_SEARCH_CATALOG.filter((name) => name.toLowerCase().includes(q))
    .sort((a, b) => {
      const al = a.toLowerCase()
      const bl = b.toLowerCase()
      const aPrefix = al.startsWith(q)
      const bPrefix = bl.startsWith(q)
      if (aPrefix !== bPrefix) return aPrefix ? -1 : 1
      return al.localeCompare(bl)
    })
    .slice(0, limit)
}

function suggestedFromRoleRules(role) {
  const rl = role.toLowerCase()
  for (const rule of ROLE_RULES) {
    if (rule.re.test(rl)) return [...rule.skills]
  }
  return []
}

/** @param {Record<string, unknown>} s profile draft */
export function suggestedSkillChipsForProfile(s) {
  const role = String(s?.role || '').trim()
  const exp = s?.exp
  const isFresher = exp === 'fresher' || !exp || exp === ''

  if (role) {
    const mapped = getSkillsForRole(role)
    if (mapped.length) return mapped
    const fromRules = suggestedFromRoleRules(role)
    if (fromRules.length) return fromRules
  }

  if (isFresher || !role) {
    return roleSkillMap._general?.length ? [...roleSkillMap._general] : [...GENERIC_FRESHER_SKILLS]
  }

  return [
    ...(roleSkillMap._general?.slice(0, 3) ?? GENERIC_FRESHER_SKILLS.slice(0, 3)),
    'Stakeholder communication',
    'Process adherence',
    'Data accuracy',
  ]
}

export { roleSkillMap }
export default roleSkillMap